example.correct_output:
{
  "productive_contradictions": [{
    "tension": "The author simultaneously advocates for wide, agenda-free cross-domain consumption and for deep, focused commitment to one domain at a time.",
    "pole_a": {
      "claim": "Creativity requires promiscuous, agenda-free consumption across unrelated domains — the raw material of cross-domain collision.",
      "supporting_quote": "Read widely, without agenda. Let the connections form on their own schedule, not yours. Cross-domain collision is not a technique. It is a posture."
    },
    "pole_b": {
      "claim": "Accumulating inputs without commitment is an amateur mistake; mastery and original output require sustained, focused attention on one domain at a time.",
      "supporting_quote": "The discipline of making requires, above all else, the discipline of finishing. Choose your domain. Dig deep. Mastery comes from sustained, focused attention on one thing at a time, not from restless wandering between them."
    },
    "generative_insight": "Neither pole alone produces original work: wide absorption without depth creates restless dilettantism; deep focus without cross-domain input produces refined repetition. The productive model is sequential alternation between phases — wide accumulation, then deep excavation — a rhythm the author eventually names explicitly in Chapter 14.",
    "authenticity_signal": "A voice that only advocated breadth would comfort perpetual learners who never ship; one that only advocated focus would ignore how breakthrough ideas actually form. The author is real precisely because they hold both in tension and acknowledge the conflict openly rather than smoothing it away."
  }]
}

